var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"무력화 완료.","JPN":"制圧完了。","ENG":"Threat neutralized.","TWN":"壓制完畢。 "},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그럼, 이대로 마무리를…….","JPN":"さて、あとはとどめを……","ENG":"Then, it's time to end...","TWN":"最後就……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"<color=#ff3636>결국…… 모든 걸 잊어버린 거야? </color>","JPN":"<color=#ff3636>結局……すべてを忘れてしまったの？</color>","ENG":"<color=#ff3636>Have you... forgotten everything?</color>","TWN":"<color=#ff3636>結果……你全都忘了嗎</color>"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그림자의 어설픈 역할 놀이에 어울려줄 생각은 없다.","JPN":"シャドウの猿芝居に付き合っている暇はない。","ENG":"I have no intentions of playing this stupid game with you, Shadow.","TWN":"我沒心情陪暗影玩什麼角色扮演的遊戲。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"도플갱어 타입인가? 너의 원본은 어디 있지?","JPN":"ドッペルシャドウか？　オリジナルはどこにいる？","ENG":"Are you a Doppelganger-type? Where is your original?","TWN":"你是二重身嗎？本體在哪？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"<color=#ff3636>큭, 큭크큭…… 그래. 결국 이런 결말이었어. </color>","JPN":"<color=#ff3636>くっ、くくくっ……そう。最初からこういう結末ってわかっていた。</color>","ENG":"<color=#ff3636>Ke, kekeke... Yes. It was supposed to end like this.</color>","TWN":"<color=#ff3636>咳，咳咳……結局果然是這樣。</color>  "},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"<color=#ff3636>결국 깊은 어둠은 밝힐 수 없고, 우린 헛된 짓을 했다는 것을. </color>","JPN":"<color=#ff3636>暗闇を照らすことなんて不可能で、全部無駄な足掻きだった。</color>","ENG":"<color=#ff3636>You couldn't illuminate the darkness, and all we did was in vain.</color>","TWN":" <color=#ff3636>黑暗終究無法被照亮，我們所做的一切都是徒勞無功。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"<color=#ff3636>당신이 그 결과를 증명하고 있어. </color>","JPN":"<color=#ff3636>あなたが、それを証明している。</color>","ENG":"<color=#ff3636>You proved it.</color>","TWN":"<color=#ff3636>你現在就在證明這一點。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"<color=#ff3636>아디트야. </color>","JPN":"<color=#ff3636>アーディティヤ。</color>","ENG":"<color=#ff3636>Aditya.</color>","TWN":"<color=#ff3636>阿迪亞。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……소멸했군. 원본을 흡수했다면 이렇게 불안정한 모습은 아니었을 텐데.","JPN":"……消滅したな。オリジナルを吸収していたのなら、ここまで不安定な姿ではなかったはずだ。","ENG":"...She's gone. If she had absorbed her original, she wouldn't have been this unstable.","TWN":"……消失了。如果已經吸收掉本體的話，應該不至於會如此不穩定。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"워, 원본을 흡수해요? 그림자가요?","JPN":"お、オリジナルを吸収するって、シャドウがですか？","ENG":"A-absorb her original? The Shadow?","TWN":"什麼，暗影會吸收本體嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"도플갱어 타입 그림자는 완전해지기 위해 원본이 되는 인간을 흡수하고 싶어 한다.","JPN":"ドッペルシャドウは己を完全なものとするために、オリジナルとなる人間を吸収したがる。","ENG":"Doppelganger-type Shadows want to absorb their original human to become whole.","TWN":"聽說二重身暗影為了要變得完整，會試圖吸收本體。 "},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그렇게 된다면 힘, 기억, 원본에 해당하는 모든 것을 자기 것으로 만들 수 있으니까.","JPN":"そうすれば力、記憶、オリジナルが持っているもの全てを自分のものにできるからな。","ENG":"Because by doing so, they will make the original's strength and memories their own.","TWN":"一旦成功，就能將力量、記憶和屬於本體的一切據為己有。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"윽…….","JPN":"うっ……","ENG":"Ngh...","TWN":"唔……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"그러니 앞으로 ■■■■■.","JPN":"だから、前に■■■■■■■。","ENG":"So, move ■■■■■.","TWN":"<color=#ffd34c>所以，背負 ■■■■■，</color>"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"■■의 ■지■ ■■■아■.","JPN":"■■■の■志■■■継■■。","ENG":"And ■■y ■■ ■■■ne's ■ll.","TWN":"■■持■■■■。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"괜찮으세요? 어디 상처 좀 봐요.","JPN":"怪我したんですか？　見せてください。","ENG":"Are you okay? Let's take a look at your wounds.","TWN":"你還好嗎？讓我看看你的傷口。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"몸은 괜찮아. 저 그림자가…… 날 아는 척을 해서 좀 놀랐을 뿐이야.","JPN":"いや、問題ない。さっきのシャドウが……私を知っているかのような態度で少し驚いただけだ。","ENG":"My body's fine. I was just taken aback... that the Shadow pretended to know who I was.","TWN":"我身體沒事。只是那個暗影……假裝認識我，所以我有點嚇到。 "},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"저 그림자의 원본이 나와 알던 사이인 것 같긴 하지만.","JPN":"おそらくオリジナルが、私とは知り合いだったのだろう。","ENG":"I think that Shadow's original and I knew each other at one point.","TWN":"那個暗影的本體，似乎認識我。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…… "},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"일단 이 도시에서 나가요.","JPN":"とりあえず、この都市を出ましょう。","ENG":"First, let's get out of this city.","TWN":"先離開這裡吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"뭐? 하지만…….","JPN":"出る？　しかし……","ENG":"What? But...","TWN":"什麼？可是……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"개인의 소망보단 목숨이라면서요. 위험하단 걸 알았으니까 그냥 나가자고요.","JPN":"自分の願いより命を優先する、ですよね。危険な場所だとわかったので、もう出ましょう。","ENG":"You said that one's life is more important than one's wishes. I understand that it's dangerous here, so let's just go.","TWN":"不是你說的嗎？個人的私慾不比性命重要。既然知道這裡危險，就趕快離開吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"기억이나, 아버지나 없어도 살아갈 수는 있잖아요. 굳이 목숨이랑 맞바꿀 것까지는…….","JPN":"お父さんや過去の記憶がなくても生きてはいけますから。命よりそっちを優先する必要はないと思いますし……","ENG":"I can live without a father or my memories. But it's not worth trading my life–","TWN":"就算沒有記憶或爸爸，我們還是能夠活下去。沒必要拿命去換……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으, 으아아! 땅이 흔들리고 있어요!","JPN":"うっ、うああっ！　地面が揺れ出しました！","ENG":"W-whoa! The ground's shaking!","TWN":"啊啊啊！地在震動！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"우, 우와악?! 저, 저게 뭐야?!","JPN":"う、うわあっ！？　あ、あれは何！？","ENG":"W-what?! W-what the heck is that?!","TWN":"我的天天天哪？！那是什麼？！ "},"stage":{"bg":"VARUNA_04_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"고래? 침식체? 무지하게 큰 녀석이에요! 저 녀석이 바로……?","JPN":"クジラ？　侵食体？　とんでもない大きさです！　もしかしてあいつが……？","ENG":"A whale? C.O.? It's huge! Is that...?","TWN":"是鯨魚？還是侵蝕體？體型好龐大！那傢伙就是……？"},"stage":{"bg":"VARUNA_04_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"저건 대체……?","JPN":"あれはいったい……？","ENG":"What is that...?","TWN":" 那到底是什麼？"},"stage":{"bg":"VARUNA_04_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};